<template>
  <div>
<!--    <SpPlatformTip h5 app alipay />-->
    <el-tabs v-model="activeName" type="card" @tab-click="handleClick">
      <el-tab-pane label="基礎配置" name="base">
        <el-form ref="form" label-width="200px">
          <el-form-item label="是否開啟交易包裝選項：">
            <el-switch
              v-model="form.config.is_open"
              active-color="#13ce66"
              inactive-color="#ff4949"
            />
          </el-form-item>
          <el-form-item label="包裝名稱：">
            <el-input v-model="form.config.packName" style="width: 300px" />
          </el-form-item>
          <el-form-item label="包裝說明：">
            <el-input v-model="form.config.packDes" type="textarea" style="width: 300px" />
          </el-form-item>
          <div class="section-footer with-border content-center">
            <el-button v-loading="loading" type="primary" @click="onSubmit"> 儲存 </el-button>
          </div>
        </el-form>
      </el-tab-pane>
    </el-tabs>
  </div>
</template>
<script>
import { getTeadeSetting, setTradeSetting } from '@/api/trade'
export default {
  data() {
    return {
      activeName: 'base',
      loading: false,
      form: {
        config: {
          packName: '',
          packDes: '',
          is_open: false
        }
      }
    }
  },
  mounted() {
    this.getConfig()
  },
  methods: {
    handleClick() {
      this.getConfig()
    },
    getConfig() {
      getTeadeSetting().then((response) => {
        this.form.config = response.data.data
      })
    },
    onSubmit() {
      this.loading = true
      setTradeSetting(this.form)
        .then((response) => {
          this.$message({
            type: 'success',
            message: '儲存成功'
          })
          this.loading = false
        })
        .catch((error) => {
          this.loading = false
        })
    }
  }
}
</script>
<style scoped lang="scss">
.el-row {
  margin-bottom: 10px;
  .frm-tips {
    color: #ff0000;
  }
}
</style>
